//! D.PERC.ENCODING.1 — Delta encoding functions.
//!
//! The algebra that converts observations into Deltas.
//! encode_relational: entities → antisymmetric matrix.
//! encode_grid_objects: grid → m=4 adjacency boundary Delta.
//! The perception module produces Deltas. The engine resolves them.

use super::*;
use crate::engine::*;
use num_bigint::BigInt;
use num_traits::{Zero, One};

pub fn encode_relational(entities: &[Vec<Q>]) -> Delta {
    let n = entities.len();
    if n == 0 { return Delta::zero(1, 1); }
    let m = entities[0].len();
    if m == 0 { return Delta::zero(n, 1); }

    let mut delta = Delta::zero(n, m);
    for i in 0..n {
        for j in (i + 1)..n {
            let mut coords = Vec::with_capacity(m);
            let mut neg_coords = Vec::with_capacity(m);
            for l in 0..m {
                let diff = if l < entities[j].len() && l < entities[i].len() {
                    &entities[j][l] - &entities[i][l]
                } else {
                    Q::zero()
                };
                neg_coords.push(-&diff);
                coords.push(diff);
            }
            delta.entries[i][j] = coords;
            delta.entries[j][i] = neg_coords;
        }
    }
    delta
}

/// Encode clusters as entities — object-level Delta.
///
/// When comprehension says "objects exist," the system encodes at the
/// object level instead of the cell level. Each CohesionCluster becomes
/// one entity with coordinates: (value, centroid_row, centroid_col, size).
///
/// A 441-cell grid with 3 objects becomes a 3-entity Delta.
/// The same algebra operates on it — C(Δ), coordinator, resolution.
/// The displacement between object centroids IS a relational coordinate.
/// The value difference IS a relational coordinate. The algebra resolves
/// coherence at the object level, not the cell level.
pub fn encode_clusters_as_entities(
    clusters: &[CohesionCluster],
    cols: usize,
    background_value: i64,
) -> (Delta, Vec<Vec<Q>>) {
    let objects: Vec<&CohesionCluster> = clusters.iter()
        .filter(|c| c.value != background_value && !c.cell_indices.is_empty())
        .collect();

    if objects.is_empty() {
        return (Delta::zero(1, 1), vec![]);
    }

    // Each object entity has m=4 coordinates:
    // [value, centroid_row, centroid_col, size]
    let entities: Vec<Vec<Q>> = objects.iter().map(|cluster| {
        let (cr, cc) = cluster_centroid(cluster, cols);
        vec![
            Q::new(BigInt::from(cluster.value), BigInt::from(1)),
            Q::new(BigInt::from(cr as i64), BigInt::from(1)),
            Q::new(BigInt::from(cc as i64), BigInt::from(1)),
            Q::new(BigInt::from(cluster.cell_indices.len() as i64), BigInt::from(1)),
        ]
    }).collect();

    let delta = encode_relational(&entities);
    (delta, entities)
}

/// Encode clusters as ranked entities — holonomic entity vectors.
///
/// Properties are RANK-NORMALIZED among same-value peers in this grid.
/// Rank = count of same-value peers with strictly smaller property value.
/// Rank is the holonomic invariant: preserved across scale/orientation changes.
///
/// Entity vector m=7: [value, centroid_r, centroid_c, rank_bbox_gap, rank_mass, rank_β₁, rank_interior]
/// Dims 0-2: absolute (value, position) for spatial matching and value transmutation.
/// Dims 3-6: ranked (topology, mass) for inter-entity discrimination.
pub fn encode_clusters_ranked(
    clusters: &[CohesionCluster],
    cols: usize,
    background_value: i64,
) -> Vec<Vec<Q>> {
    let objects: Vec<(usize, &CohesionCluster)> = clusters.iter().enumerate()
        .filter(|(_, c)| c.value != background_value && !c.cell_indices.is_empty())
        .collect();

    if objects.is_empty() { return vec![]; }

    // Compute raw properties
    struct ClusterProps { value: i64, cr: i64, cc: i64, bbox_gap: i64, mass: i64, beta1: i64, interior: i64 }
    let props: Vec<ClusterProps> = objects.iter().map(|(_, cl)| {
        let (cr, cc) = cluster_centroid(cl, cols);
        let (mr, mc, xr, xc) = cl.bbox;
        let bbox_area = (xr.saturating_sub(mr) + 1) * (xc.saturating_sub(mc) + 1);
        ClusterProps {
            value: cl.value,
            cr: cr as i64, cc: cc as i64,
            bbox_gap: bbox_area as i64 - cl.cell_indices.len() as i64,
            mass: cl.cell_indices.len() as i64,
            beta1: cl.betti_1 as i64,
            interior: cl.interior_cells.len() as i64,
        }
    }).collect();

    // Rank among same-value peers
    props.iter().map(|p| {
        let peers: Vec<&ClusterProps> = props.iter().filter(|q| q.value == p.value).collect();
        let rank = |val: i64, extract: &dyn Fn(&ClusterProps) -> i64| -> i64 {
            peers.iter().filter(|q| extract(q) < val).count() as i64
        };
        vec![
            Q::new(BigInt::from(p.value), BigInt::from(1)),
            Q::new(BigInt::from(p.cr), BigInt::from(1)),
            Q::new(BigInt::from(p.cc), BigInt::from(1)),
            Q::new(BigInt::from(rank(p.bbox_gap, &|q| q.bbox_gap)), BigInt::from(1)),
            Q::new(BigInt::from(rank(p.mass, &|q| q.mass)), BigInt::from(1)),
            Q::new(BigInt::from(rank(p.beta1, &|q| q.beta1)), BigInt::from(1)),
            Q::new(BigInt::from(rank(p.interior, &|q| q.interior)), BigInt::from(1)),
        ]
    }).collect()
}

/// Convenience: encode flat integer entities as relational Delta.
/// Each entity is a single integer value → m=1.
pub fn encode_relational_i64(values: &[i64]) -> Delta {
    let entities: Vec<Vec<Q>> = values.iter()
        .map(|&v| vec![Q::new(BigInt::from(v), BigInt::from(1))])
        .collect();
    encode_relational(&entities)
}

