// PERC.1 — Grid-to-Delta Encoder (semantic convenience, not primary path)
// ═══════════════════════════════════════════════════════════════════════

/// Encode a flat grid of integer values as an antisymmetric Delta.
/// Grid cells become Delta dimensions. Δ_ij = Q(value_j - value_i, 1).
/// Antisymmetric by construction: (v_j - v_i) = -(v_i - v_j).
///
/// For an NxM grid with K=N*M cells, produces a K×K Delta with m=1.
/// C(Δ) = 0 iff all cell-value differences are transitively consistent.
pub fn encode_grid(values: &[i64], rows: usize, cols: usize) -> Delta {
    let n = values.len();
    assert_eq!(n, rows * cols, "grid dimensions must match value count");

    let mut delta = Delta::zero(n, 1);
    for i in 0..n {
        for j in (i + 1)..n {
            let diff = Q::new(BigInt::from(values[j] - values[i]), BigInt::from(1));
            delta.entries[i][j] = vec![diff.clone()];
            delta.entries[j][i] = vec![-diff];
        }
    }
    delta
}

/// Encode a grid as OBJECTS WITH DIRECTIONALITY — three-dimensional differential.
///
/// Each cell is an object with three properties:
///   m=0: identity (value difference)
///   m=1: row displacement (row_j - row_i)
///   m=2: column displacement (col_j - col_i)
///
/// The cocycle condition checks transitivity of ALL THREE simultaneously.
/// A valid spatial transformation must be consistent in value, position,
/// AND direction. The trajectory is readable from the position components.
///
/// This resolves the dimensional collapse: the system reads OBJECTS
/// with directionality, not VALUES at locations.
pub fn encode_grid_objects(values: &[i64], rows: usize, cols: usize) -> Delta {
    let n = values.len();
    assert_eq!(n, rows * cols);

    // m=4: identity, row, col, adjacency_boundary
    // Coordinates 0-2 are coboundaries (v_j - v_i). C(Δ) = 0 on these — trivially coherent.
    // Coordinate 3 is the adjacency boundary: nonzero ONLY for grid-adjacent cells.
    // This is NOT a coboundary — it depends on edge structure, not vertex functions.
    // Cocycle equation fails: adj(i,j) + adj(j,k) ≠ adj(i,k) when i-k not adjacent.
    // C(Δ) > 0 on coordinate 3 → the algebra has signal to work with.
    // This IS comprehension entering the encoding: spatial structure that
    // coboundary coordinates cannot represent.
    let mut delta = Delta::zero(n, 4);
    for i in 0..n {
        let ri = (i / cols) as i64;
        let ci = (i % cols) as i64;
        for j in (i + 1)..n {
            let rj = (j / cols) as i64;
            let cj = (j % cols) as i64;

            let identity_diff = Q::new(BigInt::from(values[j] - values[i]), BigInt::from(1));
            let row_diff = Q::new(BigInt::from(rj - ri), BigInt::from(1));
            let col_diff = Q::new(BigInt::from(cj - ci), BigInt::from(1));

            // Adjacency boundary: nonzero only for Manhattan-adjacent cells.
            // Encodes the value difference AT boundaries — spatial comprehension.
            let manhattan = (ri - rj).abs() + (ci - cj).abs();
            let adj_boundary = if manhattan == 1 {
                Q::new(BigInt::from(values[j] - values[i]), BigInt::from(1))
            } else {
                Q::zero()
            };

            delta.entries[i][j] = vec![identity_diff.clone(), row_diff.clone(), col_diff.clone(), adj_boundary.clone()];
            delta.entries[j][i] = vec![-identity_diff, -row_diff, -col_diff, -adj_boundary];
        }
    }
    delta
}

/// Encode ONLY the non-zero cells as objects with directionality.
/// Reduces dimensionality dramatically: instead of N×N for all cells,
/// only K×K where K = number of non-zero cells.
/// The trajectory of the pattern IS the spatial arrangement of these objects.
pub fn encode_nonzero_objects(values: &[i64], rows: usize, cols: usize) -> (Delta, Vec<(usize, usize, i64)>) {
    let objects: Vec<(usize, usize, i64)> = (0..rows)
        .flat_map(|r| (0..cols).map(move |c| (r, c, values[r * cols + c])))
        .filter(|(_, _, v)| *v != 0)
        .collect();

    let k = objects.len();
    if k == 0 { return (Delta::zero(1, 3), objects); }

    let mut delta = Delta::zero(k, 3);
    for i in 0..k {
        for j in (i + 1)..k {
            let (ri, ci, vi) = objects[i];
            let (rj, cj, vj) = objects[j];

            let identity_diff = Q::new(BigInt::from(vj as i64 - vi as i64), BigInt::from(1));
            let row_diff = Q::new(BigInt::from(rj as i64 - ri as i64), BigInt::from(1));
            let col_diff = Q::new(BigInt::from(cj as i64 - ci as i64), BigInt::from(1));

            delta.entries[i][j] = vec![identity_diff.clone(), row_diff.clone(), col_diff.clone()];
            delta.entries[j][i] = vec![-identity_diff, -row_diff, -col_diff];
        }
    }

    (delta, objects)
}

/// Encode a grid with multi-channel (one-hot color encoding).
/// Each color channel l ∈ [0, num_colors) gets its own coordinate dimension.
/// Δ_ij,l = indicator(cell_j == l) - indicator(cell_i == l).
/// Captures color permutations and substitutions that single-channel misses.
pub fn encode_grid_multichannel(values: &[i64], rows: usize, cols: usize, num_colors: usize) -> Delta {
    let n = values.len();
    assert_eq!(n, rows * cols);

    let mut delta = Delta::zero(n, num_colors);
    for i in 0..n {
        for j in (i + 1)..n {
            let mut coords = vec![Q::zero(); num_colors];
            for l in 0..num_colors {
                let vi = if values[i] == l as i64 { Q::one() } else { Q::zero() };
                let vj = if values[j] == l as i64 { Q::one() } else { Q::zero() };
                coords[l] = &vj - &vi;
            }
            let neg_coords: Vec<Q> = coords.iter().map(|c| -c.clone()).collect();
            delta.entries[i][j] = coords;
            delta.entries[j][i] = neg_coords;
        }
    }
    delta
}

/// Encode only spatially adjacent cells (4-connected grid neighborhood).
/// Produces a sparse Delta — only neighbors have nonzero entries.
/// Dramatically reduces effective size: ~4*N entries instead of N².
pub fn encode_grid_adjacent(values: &[i64], rows: usize, cols: usize) -> Delta {
    let n = values.len();
    assert_eq!(n, rows * cols);

    let mut delta = Delta::zero(n, 1);
    for r in 0..rows {
        for c in 0..cols {
            let i = r * cols + c;
            // Right neighbor
            if c + 1 < cols {
                let j = r * cols + (c + 1);
                let diff = Q::new(BigInt::from(values[j] - values[i]), BigInt::from(1));
                delta.entries[i][j] = vec![diff.clone()];
                delta.entries[j][i] = vec![-diff];
            }
            // Down neighbor
            if r + 1 < rows {
                let j = (r + 1) * cols + c;
                let diff = Q::new(BigInt::from(values[j] - values[i]), BigInt::from(1));
                delta.entries[i][j] = vec![diff.clone()];
                delta.entries[j][i] = vec![-diff];
            }
        }
    }
    delta
}

