// PERC.2 — Transformation-to-Residual Mapper
// ═══════════════════════════════════════════════════════════════════════

/// Encode the TRANSFORMATION between input and output grids.
/// Δ_ij = (O_j - O_i) - (I_j - I_i) = change in relationship from input to output.
/// C(Δ_transform) = 0 iff the transformation is transitively consistent —
/// a uniform rule explains all cell changes.
pub fn encode_transformation(input: &[i64], output: &[i64]) -> Delta {
    let n = input.len();
    assert_eq!(n, output.len(), "input and output must have same length");

    let mut delta = Delta::zero(n, 1);
    for i in 0..n {
        for j in (i + 1)..n {
            let input_diff = input[j] - input[i];
            let output_diff = output[j] - output[i];
            let transform_diff = Q::new(BigInt::from(output_diff - input_diff), BigInt::from(1));
            delta.entries[i][j] = vec![transform_diff.clone()];
            delta.entries[j][i] = vec![-transform_diff];
        }
    }
    delta
}

/// Measure how well a transformation rule is captured by the encoding.
/// Returns (coherence, num_residuals) — coherence=0 means perfect transitive rule.
pub fn transformation_coherence(input: &[i64], output: &[i64]) -> (Q, u32) {
    let delta = encode_transformation(input, output);
    let c = coherence_functional(&delta);
    let mut count = 0u32;
    for_each_residual(&delta, |_, _, _, _, _| count += 1);
    (c, count)
}

