// PERC.3 — Action-to-Operator Mapper
// ═══════════════════════════════════════════════════════════════════════

/// Map a grid cell modification to an operator on the Delta.
/// "Set cell at index `cell` to value `new_value`" changes relationships
/// of that cell with all others.
pub fn action_set_cell(grid_size: usize, cell: usize, old_value: i64, new_value: i64) -> Operator {
    let diff = new_value - old_value;
    let dims = matrix::independent_dims(grid_size);
    let mut epsilon = vec![Q::zero(); dims.len()];

    // The cell's relationships with all other cells change by `diff`
    for (idx, &(r, s)) in dims.iter().enumerate() {
        if r == cell {
            epsilon[idx] = Q::new(BigInt::from(diff), BigInt::from(1));
        } else if s == cell {
            epsilon[idx] = Q::new(BigInt::from(-diff), BigInt::from(1));
        }
    }

    matrix::operator_from_epsilons(&epsilon, &dims, grid_size, 0)
        .unwrap_or_else(|| {
            // Fallback: identity operator
            Operator {
                id: 0,
                matrix: matrix::identity(grid_size),
                matrix_inv: matrix::identity(grid_size),
                det_sign_positive: true,
            }
        })
}

/// Given a Delta (encoded grid state), find the best cell to modify
/// using the coherence gradient. Returns (cell_index, direction).
pub fn suggest_action(delta: &Delta) -> Option<(usize, i64)> {
    let resolution = coordinator::resolve(delta);
    if resolution.coherence_before.is_zero() { return None; }

    // Find the direction with largest |epsilon|
    let mut best_idx = 0;
    let mut best_mag = Q::zero();
    for (idx, eps) in resolution.epsilon.iter().enumerate() {
        let mag = if eps < &Q::zero() { -eps.clone() } else { eps.clone() };
        if mag > best_mag {
            best_mag = mag;
            best_idx = idx;
        }
    }

    if best_mag.is_zero() { return None; }

    // The direction (r, s) tells us which cell pair to adjust
    let (r, _s) = resolution.directions[best_idx];
    // Positive epsilon → increase cell r's value; negative → decrease
    let direction = if resolution.epsilon[best_idx] > Q::zero() { 1 } else { -1 };
    Some((r, direction))
}

