// PERC.4 — Delta-to-Grid Decoder
// ═══════════════════════════════════════════════════════════════════════

/// Decode a Delta back to grid values.
/// Uses cell 0 as reference (value = reference_value).
/// Reconstructs other cells from Δ_{0,j}: value_j = reference + Δ_{0,j}.
pub fn decode_delta(delta: &Delta, reference_value: i64) -> Vec<i64> {
    let n = delta.dim;
    let mut values = vec![reference_value; n];
    for j in 1..n {
        if !delta.entries[0][j].is_empty() && !delta.entries[0][j][0].is_zero() {
            // value_j = reference + Δ_{0,j}
            let ratio = &delta.entries[0][j][0];
            // Convert rational to integer (round toward zero)
            let numer: i64 = ratio.numer().try_into().unwrap_or(0);
            let denom: i64 = ratio.denom().try_into().unwrap_or(1);
            values[j] = reference_value + numer / denom.max(1);
        }
    }
    values
}

/// Given input grid, output grid (for reference cell), and transformation Delta,
/// predict the full output.
///
/// The transform Delta captures DIFFERENTIAL changes only.
/// The absolute shift is computed from the known output of cell 0.
/// For derive_transformation, we pass the actual output's cell 0 value.
pub fn derive_output(input: &[i64], transform_delta: &Delta) -> Vec<i64> {
    let n = input.len();
    let mut output = input.to_vec();

    for j in 1..n {
        if !transform_delta.entries[0][j].is_empty() {
            let transform_diff = &transform_delta.entries[0][j][0];
            let input_diff = input[j] - input[0];
            let numer: i64 = transform_diff.numer().try_into().unwrap_or(0);
            let denom: i64 = transform_diff.denom().try_into().unwrap_or(1);
            let output_diff = input_diff + numer / denom.max(1);
            output[j] = output[0] + output_diff;
        }
    }
    output
}

/// Predict output with known reference value for cell 0.
/// This captures absolute shifts that the differential encoding misses.
pub fn derive_output_with_reference(input: &[i64], transform_delta: &Delta, output_cell_0: i64) -> Vec<i64> {
    let n = input.len();
    let mut output = vec![output_cell_0; n];

    for j in 1..n {
        if !transform_delta.entries[0][j].is_empty() {
            let transform_diff = &transform_delta.entries[0][j][0];
            let input_diff = input[j] - input[0];
            let numer: i64 = transform_diff.numer().try_into().unwrap_or(0);
            let denom: i64 = transform_diff.denom().try_into().unwrap_or(1);
            let output_diff = input_diff + numer / denom.max(1);
            output[j] = output_cell_0 + output_diff;
        }
    }
    output
}

/// Full encode → resolve → decode pipeline for a transformation.
/// Returns (predicted_output, coherence_before, coherence_after).
///
/// Uses output[0] as the reference value for absolute shift reconstruction.
pub fn derive_transformation(input: &[i64], output: &[i64]) -> (Vec<i64>, Q, Q) {
    let transform = encode_transformation(input, output);
    let c_before = coherence_functional(&transform);
    let ref_val = output[0];

    if let Some((op, _resolution)) = coordinator::propose(&transform) {
        if let Ok(resolved) = op.apply(&transform) {
            let projected = crate::engine::pi_g_project(&resolved);
            let c_after = coherence_functional(&projected);
            let derived = derive_output_with_reference(input, &projected, ref_val);
            return (derived, c_before, c_after);
        }
    }

    let derived = derive_output_with_reference(input, &transform, ref_val);
    (derived, c_before.clone(), c_before)
}

// ═══════════════════════════════════════════════════════════════════════
// D.PERCEPTION.1 — The Perception Operator
//
// Perception is not input processing. It is not prediction. It is the
// active derivation of what an observation MEANS by measuring the
// coherence between the system's understanding and the empirical data.
//
// P(observation) = derive output from understanding + measure residual
//
// The residual classifies the perception:
//   residual = 0  → Recognition: understanding covers the observation
//   residual > 0, resolvable → Transmutation: understanding can grow to cover it
//   residual > 0, irreducible → Axiomatically unreachable: the system knows
//                                 exactly what it doesn't know, by how much,
//                                 in which relational directions
// ═══════════════════════════════════════════════════════════════════════
